function myNew(o, ...args) {
  // \u521B\u5EFA\u5BF9\u8C61
  const obj = {};
  // \u94FE\u63A5\u5BF9\u8C61
  obj.__proto__ = o.prototype;
  // \u7ED1\u5B9Athis
  let res = o.call(obj, ...args);
  return res instanceof Object ? res : obj;
}
const user = myNew(User, 'tf', 20);
console.log(user);
