import React, { useState, useEffect } from 'react';

function App() {
  const [count, setCount] = useState(1);
  const changeCount = () => {
    setCount(count + 1);
  };
  return (
    <div className="App">
      <p>\u70B9\u51FB\u6B21\u6570\uFF1A{count}</p>
      <button onClick={changeCount}>\u52A01</button>
    </div>
  );
}

export default App;
